import{o as n,c as a,b as s}from"./app.3132835d.js";const t='{"title":"深拷贝","description":"深拷贝的简单实现以及进阶","frontmatter":{"title":"深拷贝","date":"2021-05-25","tags":["Javascript"],"description":"深拷贝的简单实现以及进阶"},"headers":[{"level":2,"title":"JS的数据类型","slug":"js的数据类型"},{"level":2,"title":"深浅拷贝定义","slug":"深浅拷贝定义"},{"level":3,"title":"浅拷贝","slug":"浅拷贝"},{"level":3,"title":"深拷贝","slug":"深拷贝"},{"level":2,"title":"代码实现","slug":"代码实现"},{"level":3,"title":"一行代码","slug":"一行代码"},{"level":3,"title":"基础版","slug":"基础版"},{"level":3,"title":"对象中有循环引用","slug":"对象中有循环引用"},{"level":2,"title":"进阶文章","slug":"进阶文章"}],"relativePath":"blog/deepClone.md","lastUpdated":1622014680084}',p={},e=s('<h2 id="js的数据类型"><a class="header-anchor" href="#js的数据类型" aria-hidden="true">#</a> JS的数据类型</h2><ul><li>基本类型（undefined、null、string、number、boolean、symbol（ES6））</li><li>引用类型（Object、Array、RegExp、Date、Function）</li></ul><h2 id="深浅拷贝定义"><a class="header-anchor" href="#深浅拷贝定义" aria-hidden="true">#</a> 深浅拷贝定义</h2><h3 id="浅拷贝"><a class="header-anchor" href="#浅拷贝" aria-hidden="true">#</a> 浅拷贝</h3><p>创建一个新对象，这个对象有着原始对象属性值的一份精确拷贝。如果属性是基本类型，拷贝的就是基本类型的值，如果属性是引用类型，拷贝的就是内存地址 ，所以如果其中一个对象改变了这个地址，就会影响到另一个对象。</p><h3 id="深拷贝"><a class="header-anchor" href="#深拷贝" aria-hidden="true">#</a> 深拷贝</h3><p>将一个对象从内存中完整的拷贝一份出来,从堆内存中开辟一个新的区域存放新对象,且修改新对象不会影响原对象。</p><h2 id="代码实现"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2><h3 id="一行代码"><a class="header-anchor" href="#一行代码" aria-hidden="true">#</a> 一行代码</h3><div class="language-js"><pre><code><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre></div><h3 id="基础版"><a class="header-anchor" href="#基础版" aria-hidden="true">#</a> 基础版</h3><p>target考虑数组和对象</p><div class="language-js"><pre><code><span class="token function">deepClone</span><span class="token punctuation">(</span><span class="token parameter">target</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> target <span class="token operator">===</span> <span class="token string">&#39;object&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">let</span> cloneTarget <span class="token operator">=</span> Array<span class="token punctuation">.</span><span class="token function">isArray</span><span class="token punctuation">(</span>target<span class="token punctuation">)</span> <span class="token operator">?</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n        <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> key <span class="token keyword">in</span> target<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n            cloneTarget<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">clone</span><span class="token punctuation">(</span>target<span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token punctuation">)</span>\n        <span class="token punctuation">}</span>\n        <span class="token keyword">return</span> cloneTarget\n    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>\n        <span class="token keyword">return</span> target\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="对象中有循环引用"><a class="header-anchor" href="#对象中有循环引用" aria-hidden="true">#</a> 对象中有循环引用</h3><div class="language-js"><pre><code><span class="token keyword">function</span> <span class="token function">deepClone</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> map <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">WeakMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> target <span class="token operator">===</span> <span class="token string">&#39;object&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">let</span> cloneTarget <span class="token operator">=</span> Array<span class="token punctuation">.</span><span class="token function">isArray</span><span class="token punctuation">(</span>target<span class="token punctuation">)</span> <span class="token operator">?</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n        <span class="token keyword">if</span> <span class="token punctuation">(</span>map<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>target<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n            <span class="token keyword">return</span> target\n        <span class="token punctuation">}</span>\n        map<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> cloneTarget<span class="token punctuation">)</span>\n        <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> key <span class="token keyword">in</span> target<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n            cloneTarget<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">clone</span><span class="token punctuation">(</span>target<span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token punctuation">,</span> map<span class="token punctuation">)</span>\n        <span class="token punctuation">}</span>\n        <span class="token keyword">return</span> cloneTarget\n    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>\n        <span class="token keyword">return</span> target\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h2 id="进阶文章"><a class="header-anchor" href="#进阶文章" aria-hidden="true">#</a> 进阶文章</h2><ul><li><a href="https://www.jianshu.com/p/785192745c10" target="_blank" rel="noopener noreferrer">https://www.jianshu.com/p/785192745c10</a></li><li><a href="https://cloud.tencent.com/developer/article/1497418" target="_blank" rel="noopener noreferrer">https://cloud.tencent.com/developer/article/1497418</a></li></ul>',17);p.render=function(s,t,p,o,c,l){return n(),a("div",null,[e])};export default p;export{t as __pageData};
